360	fn classify_error<'a>(span: &'a Span, place: &'a str, message: &'a str) -> &'a str {
361	    if span.line == 0 {
362	        return "internal error";
363	    }
364	    match place {
365	        "scanning" | "lexing" => "lexing error",
366	        "parsing" => "parsing error",
367	        "pre-transpiling" => "import error",
368	        "transpiling" => "transpilation error",
369	        "type checker" | "returned type checker" | "transpiler" => "type error",
370	        "interpreting" => "runtime error",
371	        "fetching mangled member name" => "type error",
372	        _ => match message {
373	            msg if msg.contains("unexpected") => "transpilation error",
374	            msg if msg.contains("PANIC") => "internal error",
375	            msg if msg.contains("already") => "declaration error",
376	            msg if msg.contains("not") || msg.contains("undefined") || msg.contains("Unknown") => "resolution error",
377	            msg if msg.contains("Expected") => "syntax error",
378	            _ => "error",
379	        },
380	    }
381	}
